package main

import (
	"bufio"
	"fmt"
	"os"
)

// Não mude a assinatura desta função, ela é a função chamada pelo LeetCode
func exist(grid [][]byte, word string) bool {
	_, _ = grid, word
	w := []byte(word)


	x:=0
	y:=0
	//z:=0
	for	i := 0; i < len(grid);i++{
		for j:= 0; j < len(grid[0]); i++{
			if w[0] == grid[i][j]{
				x = 1
				y = 1
				for k := 1; k < len(w); k++{
					if i+k >= len(grid) - 1{
						break
					}
					if w[k] == grid[i+k][j] {
						x++
					} else{
						break
					}
				}
				for k := 1; k < len(w); k++{
					if j+k >=len(grid[0]) - 1{
						break
					}
					if w[k] == grid[i][j+k]{
						y++
					} else {break}
				}
			}
			if x >= len(w) - 1 || y>= len(w){
				return true
			}
		}
	}


	return false
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Scan()
	var word string
	fmt.Sscanf(scanner.Text(), "%s", &word)
	grid := make([][]byte, 0)
	for scanner.Scan() {
		grid = append(grid, []byte(scanner.Text()))
	}
	if exist(grid, word) {
		fmt.Println("true")
	} else {
		fmt.Println("false")
	}
}
